ent": null, "is_current": false, "period_end": "2022-11", "work_region": null, "company_name": "대우조선해양건설㈜", "job_category": "공무", "period_start": "2006-04", "employment_type": "unknown", "resignation_reason": "경영악화", "company_name_current": null, "employment_type_signals": null}], "personal_info": {"age": 49, "email": "tess26@hanmail.net", "phone": "010-6617-2068", "gender": "여", "address": "(27465) 충북 충주시 중앙탑면 원앙4길", "birth_date": "1976-01-01", "birth_year": 1976, "name_hanja": null, "name_korean": "이정분", "photo_present": true}, "physical_info": {"height": null, "vision": null, "weight": null}, "certifications": [], "current_status": {"current_company": "경남기업", "group_join_date": "2025-11", "current_position": "차장/팀장", "current_job_function": "공무"}, "application_info": {"applied_date": "2025-12-22", "applied_field": "건축공사팀_공무", "desired_salary": "회사내규에 따름", "previous_salary": 9500}, "military_service": {"rank": null, "branch": null, "status": "해당없음", "specialty": null, "period_end": null, "period_start": null, "service_place": null}, "self_introduction": {"sections": [{"title": "지원동기", "content": "대우조선해양건설 17년, 대흥건설에서 2년, 현재 경남기업에서 현장공무 팀장으로 근무중에 있습니다. 대우조선해양건설 시절 고양지축LH현장 공무팀장으로 재직 중 경영악화에 따른 공사중단으로 퇴사하게 되었고, 공사중단 위기였던 평택고덕LH현장이 대흥건설로 대표사가 변경되어 대흥건설로 이직하여 성공적으로 공사를 마치게 되었으나 회사 경영난으로 퇴직하게 되었고, 현재 경남기업에서 현장 공무팀장으로 재직중이나 저의 업무적 능력과 미래를 고려하여 저의 능력을 귀사에서 발휘하고자 지원하였습니다."}, {"title": "주요역량", "content": "본사에서 경험한 건축현장관리, 현장에서 경험한 공무업무를 토대로 현장 원가관리, 리스크관리 역량이 특출합니다. 또한 대내/내외 업무의 뛰어난 공무관련 지식 및 실무능력과, 문제해결 능력이 탁월합니다. 아울러, 여성으로서 현장 적응에 다소 어려울거라는 편견과 달리 동료들과의 원활한 커뮤니케이션과 협력을 통해 조화롭고, 효율적인 업무를 추진하였고, 업무에 대한 책임감과 열정, 성실함, 높은 직업윤리의식을 바탕으로 발주처 및 동료들과의 높은 신뢰도로 성공적인 현장을 이끌수 있는 역량이 있습니다."}, {"title": "입사 후 포부", "content": "변화하는 건설환경에 적극적인 대응으로 리스크를 최소화하여, 성공적인 공사 및 원가관리로 현장발전에 기여하고 회사에 모범이 될 수 있도록 하겠습니다."}], "full_text": "[지원동기]\n대우조선해양건설 17년, 대흥건설에서 2년, 현재 경남기업에서 현장공무 팀장으로 근무중에 있습니다...\n[주요역량]\n본사에서 경험한 건축현장관리, 현장에서 경험한 공무업무를 토대로 현장 원가관리, 리스크관리 역량이 특출합니다...\n[입사 후 포부]\n변화하는 건설환경에 적극적인 대응으로 리스크를 최소화하여, 성공적인 공사 및 원가관리로 현장발전에 기여하고 회사에 모범이 될 수 있도록 하겠습니다."}, "resume_format_type": "portal_career_description_split", "attachments_mentioned": ["경력증명서(이정분).pdf"]}, "certificateData": {"grade": {"quality_management": "특급", "design_construction": {"job_field": "건축, 안전관리", "specialty_field": "건축시공 중급, 건설안전 초급"}, "construction_project_management": {"job_field": "건축, 안전관리", "specialty_field": "건축시공 초급, 건설안전 초급"}}, "awards": [], "training": [{"category": "설계·시공", "period_end": "2024-05-03", "course_name": "설계시공기술인계속특급전문교육(원격교육)", "institution": "건설기술교육원", "period_start": "2024-04-02"}, {"category": "품질관리", "period_end": "2021-11-01", "course_name": "품질관리기술인승급특급전문교육", "institution": "건설기술교육원", "period_start": "2021-10-25"}, {"category": "품질관리", "period_end": "2018-06-29", "course_name": "품질관리기술자승급고급전문교육", "institution": "건설기술교육원", "period_start": "2018-06-25"}, {"category": "품질관리", "period_end": "2017-07-28", "course_name": "품질관리기술자최초초급기본교육", "institution": "건설기술교육원", "period_start": "2017-07-24"}, {"category": "품질관리", "period_end": "2017-06-02", "course_name": "품질관리기술자최초초급전문교육", "institution": "건설기술교육원", "period_start": "2017-05-29"}, {"category": "설계·시공", "period_end": "2016-07-22", "course_name": "설계·시공기술자승급고급전문교육", "institution": "건설기술교육원", "period_start": "2016-07-18"}, {"category": "설계·시공", "period_end": "2015-11-27", "course_name": "설계·시공기술자승급중급전문교육", "institution": "건설기술교육원", "period_start": "2015-11-23"}, {"category": "설계·시공", "period_end": "2011-05-20", "course_name": "초급전문교육과정", "institution": "건설기술교육원", "period_start": "2011-05-16"}, {"category": "설계·시공", "period_end": "2011-04-22", "course_name": "초급기본교육과정", "institution": "건설기술교육원", "period_start": "2011-04-18"}, {"category": "설계·시공", "period_end": "2011-04-15", "course_name": "초급기본교육과정", "institution": "건설기술교육원", "period_start": "2011-04-11"}], "education": [], "penalties": {"demerits": null, "sanctions": []}, "work_history": [{"period_end": "2006-03-31", "company_name": "(주)신원씨케이", "period_start