t": "천안불당동", "is_current": false, "period_end": "2021-05", "work_region": null, "company_name": "반도엔지니어링", "job_category": "시공관리자", "period_start": "2020-11", "employment_type": "unknown", "resignation_reason": null, "company_name_current": null, "employment_type_signals": null}], "personal_info": {"age": 35, "email": "baesj0518@gmail.com", "phone": "010-9947-0518", "gender": "남", "address": "대전 동구 옛신탄진로", "birth_date": "1990-05-18", "birth_year": 1990, "name_hanja": null, "name_korean": "배성지", "photo_present": true}, "physical_info": {"height": null, "vision": null, "weight": null}, "certifications": [{"pass_date": "2016-08", "issuing_body": "한국산업인력공단", "type_and_grade": "응용지질기사", "registration_number": null}, {"pass_date": "2017-08", "issuing_body": "대한상공회의소", "type_and_grade": "컴퓨터활용능력2급", "registration_number": null}], "current_status": {"current_company": "남광토건", "group_join_date": "2023-08", "current_position": "대리", "current_job_function": "시공관리자"}, "application_info": {"applied_date": "2026-01-29", "applied_field": "건축설비_공사", "desired_salary": "회사내규에 따름", "previous_salary": null}, "military_service": {"rank": null, "branch": null, "status": null, "specialty": null, "period_end": null, "period_start": null, "service_place": null}, "self_introduction": {"sections": [{"title": "비전공자의 한계를 넘어선 성과창출의 전문가(직무능력 강점)", "content": "비록 건축설비분야를 전공하지 않았으나, 대학원에서 숙련된 문서작성 및 S/W운용능력을 바탕으로 업무를 시작하였습니다. 성실함으로 업무를 소화하고 현장의 문제들을 해결하며 가치를 증명해왔습니다. 여수 현장에서 실행 예산 대비 약 10%의 추가 이익을 창출하여 과장으로 진급하는 성과를 이뤘습니다."}, {"title": "탐구심으로 발견하고 책임감으로 해결하다(장점과 단점)", "content": "저의 강점은 ''책임감''이며 보완점은 ''탐구심''입니다. 김포 구래동 현장에서 슬리브 시공 높이 오차를 포착하여 오시공을 막아낸 경험이 있습니다. 타설 일정이 임박했음에도 도면을 교차 검토하여 수치를 조정하고 재배치하여 실질적인 손실을 막았습니다."}, {"title": "빌려 쓰는 시간에 책임을 다하는 인재(인생관 및 좌우명)", "content": "''자신에게 미안하지 않게 살자''는 좌우명으로 비전공자로서 늦게 입문한 만큼 실무 자료를 체화하고 현장에서 지식의 밀도를 높여왔습니다. 현재 국가기술자격증 취득을 위한 실기 준비 중에 있습니다."}], "full_text": "비전공자의 한계를 넘어선 성과창출의 전문가(직무능력 강점)...\n탐구심으로 발견하고 책임감으로 해결하다(장점과 단점)...\n빌려 쓰는 시간에 책임을 다하는 인재(인생관 및 좌우명)..."}, "resume_format_type": "portal_project", "attachments_mentioned": ["경력확인서(배성지).pdf"]}, "certificateData": {"grade": {"quality_management": "초급", "design_construction": {"job_field": "토목, 기계", "specialty_field": "토질·지질"}, "construction_project_management": {"job_field": "토목", "specialty_field": "토질·지질"}}, "awards": [], "training": [], "education": [{"degree": "학사[졸업]", "department": "지구환경과학부 지질환경과학과", "school_name": "충남대학교", "graduation_date": "2015-02-25"}], "penalties": {"demerits": null, "sanctions": []}, "work_history": [{"period_end": "2021-05-08", "company_name": "반도엔지니어링(주)", "period_start": "2020-11-23", "company_name_current": null}, {"period_end": "2022-02-28", "company_name": "(주)용원테크", "period_start": "2021-05-10", "company_name_current": null}, {"period_end": "2022-06-30", "company_name": "(주)용원테크", "period_start": "2022-03-01", "company_name_current": null}, {"period_end": "2022-09-30", "company_name": "(주)용원테크", "period_start": "2022-07-01", "company_name_current": null}, {"period_end": "2022-11-30", "company_name": "(주)용원테크", "period_start": "2022-10-01", "company_name_current": null}, {"period_end": "2023-02-28", "company_name": "(주)용원테크", "period_start": "2022-12-01", "company_name_current": null}, {"period_end": "2023-08-19", "company_name": "(주)한울산업개발", "period_start": "2023-03-01", "company_name_current": null}, {"period_end": null, "company_name": "남광토건(주)", "period_start": "2023-08-21", "company_name_current": null}], "document_info": {"issue_date": "2025-11-24", "total_pages": 5, "issue_number": "20251124-C01847083", "management_number": "1101273", "document_confirmation_number": "4410-7674-9547-9242"}, "personal_info": {"address": "대전 동구 옛신탄진로 51-16 나동 301호(홍도동, 홍도빌라)", "birth_date": "1990-05-18", "name_hanja": null, "name_korean": "배성지"}, "career_summary": {"by_job_specialty": [{"job_field": "기계", "recognized_days": 789, "specialty_field": "공조냉동및설비"}, {"job_field": "기계", "recognized_days": 737, "specialty_field": "건설기계"}, {"job_fi